const { BigQuery } = require('@google-cloud/bigquery');
const functions = require('@google-cloud/functions-framework');

const bigquery = new BigQuery();

const MAX_ROWS_PER_QUERY = 100000;
const MAX_PROCESSING_TIME = 520000;
const ALLOWED_DATASETS = process.env.ALLOWED_DATASETS ? process.env.ALLOWED_DATASETS.split(',') : [];
const ALLOWED_TABLES = process.env.ALLOWED_TABLES ? process.env.ALLOWED_TABLES.split(',') : [];

function validateInput(req) {
  const errors = [];
  
  if (!req.body) {
    errors.push('Request body is required');
    return errors;
  }

  const { datasetId, tableId, aggregationType, groupByField, valueField } = req.body;

  if (!datasetId || typeof datasetId !== 'string' || !/^[a-zA-Z0-9_]+$/.test(datasetId)) {
    errors.push('Invalid datasetId format');
  }

  if (!tableId || typeof tableId !== 'string' || !/^[a-zA-Z0-9_]+$/.test(tableId)) {
    errors.push('Invalid tableId format');
  }

  if (ALLOWED_DATASETS.length > 0 && !ALLOWED_DATASETS.includes(datasetId)) {
    errors.push('Dataset not in allowed list');
  }

  if (ALLOWED_TABLES.length > 0 && !ALLOWED_TABLES.includes(tableId)) {
    errors.push('Table not in allowed list');
  }

  const validAggregations = ['SUM', 'AVG', 'COUNT', 'MAX', 'MIN'];
  if (!aggregationType || !validAggregations.includes(aggregationType.toUpperCase())) {
    errors.push('Invalid aggregation type');
  }

  if (!groupByField || typeof groupByField !== 'string' || !/^[a-zA-Z0-9_]+$/.test(groupByField)) {
    errors.push('Invalid groupByField format');
  }

  if (aggregationType.toUpperCase() !== 'COUNT') {
    if (!valueField || typeof valueField !== 'string' || !/^[a-zA-Z0-9_]+$/.test(valueField)) {
      errors.push('Invalid valueField format');
    }
  }

  return errors;
}

function buildSecureQuery(datasetId, tableId, aggregationType, groupByField, valueField, projectId) {
  const fullyQualifiedTable = `\`${projectId}.${datasetId}.${tableId}\``;
  
  let aggregationExpression;
  if (aggregationType.toUpperCase() === 'COUNT') {
    aggregationExpression = 'COUNT(*)';
  } else {
    aggregationExpression = `${aggregationType.toUpperCase()}(\`${valueField}\`)`;
  }

  const query = `
    SELECT 
      \`${groupByField}\` as group_key,
      ${aggregationExpression} as aggregated_value
    FROM ${fullyQualifiedTable}
    WHERE \`${groupByField}\` IS NOT NULL
    GROUP BY \`${groupByField}\`
    ORDER BY aggregated_value DESC
    LIMIT ${MAX_ROWS_PER_QUERY}
  `;

  return query;
}

async function processLargeDataset(req, res) {
  const startTime = Date.now();
  
  try {
    const validationErrors = validateInput(req);
    if (validationErrors.length > 0) {
      res.status(400).json({
        error: 'Validation failed',
        details: validationErrors
      });
      return;
    }

    const { datasetId, tableId, aggregationType, groupByField, valueField } = req.body;
    const projectId = process.env.GCP_PROJECT || process.env.GCLOUD_PROJECT || await bigquery.getProjectId();

    const query = buildSecureQuery(datasetId, tableId, aggregationType, groupByField, valueField, projectId);

    const options = {
      query: query,
      location: process.env.BIGQUERY_LOCATION || 'US',
      maximumBytesBilled: process.env.MAX_BYTES_BILLED || '10000000000',
      timeoutMs: MAX_PROCESSING_TIME,
      useLegacySql: false,
      useQueryCache: true
    };

    console.log('Executing BigQuery aggregation', {
      datasetId,
      tableId,
      aggregationType,
      timestamp: new Date().toISOString()
    });

    const [job] = await bigquery.createQueryJob(options);
    
    const checkTimeout = () => {
      if (Date.now() - startTime > MAX_PROCESSING_TIME) {
        throw new Error('Processing timeout exceeded');
      }
    };

    let rows;
    const pollInterval = 2000;
    while (true) {
      checkTimeout();
      const [metadata] = await job.getMetadata();
      
      if (metadata.status.state === 'DONE') {
        if (metadata.status.errorResult) {
          throw new Error(`BigQuery job failed: ${metadata.status.errorResult.message}`);
        }
        [rows] = await job.getQueryResults({
          maxResults: MAX_ROWS_PER_QUERY
        });
        break;
      }
      
      await new Promise(resolve => setTimeout(resolve, pollInterval));
    }

    const processingTime = Date.now() - startTime;

    res.status(200).json({
      success: true,
      rowCount: rows.length,
      processingTimeMs: processingTime,
      data: rows,
      metadata: {
        datasetId,
        tableId,
        aggregationType,
        groupByField,
        valueField: valueField || 'N/A'
      }
    });

  } catch (error) {
    console.error('Error processing dataset:', {
      error: error.message,
      stack: error.stack,
      timestamp: new Date().toISOString()
    });

    const statusCode = error.message.includes('Validation') ? 400 : 
                       error.message.includes('timeout') ? 504 : 500;

    res.status(statusCode).json({
      error: 'Processing failed',
      message: error.message,
      timestamp: new Date().toISOString()
    });
  }
}

